SELECT AVG(strftime('%s', timestamp)) AS average_timestamp
FROM write_operations
WHERE user_id = 0;

SELECT DISTINCT u.username
FROM users u
JOIN write_operations w ON u.user_id = w.user_id;

SELECT COUNT(unit_id) AS online_units_count
FROM hardware_units
WHERE status = 'online';

SELECT unit_name, status
FROM hardware_units
WHERE status = 'online';

SELECT timestamp, value
FROM write_operations
WHERE user_id = 0;

SELECT description 
FROM hardware_units 
WHERE unit_id = 1;
